B.Bc=new A.bx("Zuh\xf6ren vor Antworten",'Das Wichtigste ist zuerst: einfach zuh\xf6ren. Nicht sofort L\xf6sungen anbieten. Verst\xe4ndnis zeigen: \u201eDas klingt wirklich schwer."',B.J,null)
